#!/usr/bin/env python3
import sys, math

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        parts = data[i].split()
        shape = parts[0]
        if shape == 'circle':
            r = float(parts[1])
            area = math.pi * r * r
        elif shape == 'square':
            s = float(parts[1])
            area = s * s
        elif shape == 'triangle':
            b = float(parts[1])
            h = float(parts[2])
            area = 0.5 * b * h
        else:
            area = 0.0
        out.append(f"{area:.2f}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

